export { TextInput } from './text-input';
export {
  NumericInputRoot,
  NumericScrubArea,
  NumericInput,
} from './numeric-input';
export { ColorInput } from './color-input';
export {
  InputGroup,
  InputGroupAddon,
  InputGroupDivider,
} from './input-group';

import { Input as BaseInput } from '@base-ui/react';
import { cn } from '@/lib/utils';

const INPUT_BASE_CLASS =
  'placeholder:text-grey-400 text-black-800 bg-grey-100 typography-body-medium hover:ring-grey-200 dark:placeholder:text-grey-400 dark:bg-grey-700 dark:text-white-1000 dark:hover:ring-grey-600 flex h-6 w-full min-w-0 items-center rounded-md px-2 ring ring-transparent outline-none selection:bg-blue-500 focus:ring-blue-500 disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-red-500 aria-invalid:ring-red-500/20 dark:focus:ring-blue-500';

function TextInput({
  className,
  ...props
}: React.ComponentProps<typeof BaseInput>) {
  return (
    <BaseInput
      {...props}
      data-slot='input'
      className={cn(INPUT_BASE_CLASS, className)}
    />
  );
}

export { TextInput, INPUT_BASE_CLASS };

'use client';

import React from 'react';
import { NumberField } from '@base-ui/react/number-field';
import { cn } from '@/lib/utils';
import { INPUT_BASE_CLASS } from './text-input';

// ----- pure helpers -----
const OPERATORS_REGEX = /[+\-*/()]/;
const PREC: Record<string, number> = {
  'u-': 3,
  '*': 2,
  '/': 2,
  '+': 1,
  '-': 1,
};
const RIGHT_ASSOC = new Set(['u-']);

const toNullableNumber = (v: unknown): number | null => {
  if (v === '' || v === undefined || v === null) return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  if (typeof v === 'string') {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  }
  return null;
};

const trimTrailingZeros = (s: string): string => {
  if (!s.includes('.')) return s;
  return s.replace(/\.0+$/, '').replace(/(\.\d*?)0+$/, '$1');
};

const evaluateExpression = (expr: string): number | null => {
  const tokens: (number | string)[] = [];
  const src = expr.replace(/\s+/g, '');
  let i = 0;
  const isDigit = (c: string) => /[0-9]/.test(c);
  while (i < src.length) {
    const c = src[i];
    if (isDigit(c) || c === '.') {
      let j = i + 1;
      while (j < src.length && (isDigit(src[j]) || src[j] === '.')) j++;
      const n = Number(src.slice(i, j));
      if (!Number.isFinite(n)) return null;
      tokens.push(n);
      i = j;
    } else if (
      c === '+' ||
      c === '-' ||
      c === '*' ||
      c === '/' ||
      c === '(' ||
      c === ')'
    ) {
      const prev = tokens[tokens.length - 1];
      if (
        c === '-' &&
        (prev === undefined ||
          (typeof prev === 'string' &&
            (prev === '+' ||
              prev === '-' ||
              prev === '*' ||
              prev === '/' ||
              prev === '(')))
      ) {
        tokens.push('u-');
        i++;
      } else {
        tokens.push(c);
        i++;
      }
    } else {
      return null;
    }
  }
  const output: (number | string)[] = [];
  const ops: string[] = [];
  for (const t of tokens) {
    if (typeof t === 'number') {
      output.push(t);
    } else if (t === '(') {
      ops.push(t);
    } else if (t === ')') {
      while (ops.length && ops[ops.length - 1] !== '(')
        output.push(ops.pop() as string);
      if (ops.pop() !== '(') return null;
    } else {
      while (
        ops.length &&
        ops[ops.length - 1] !== '(' &&
        ((RIGHT_ASSOC.has(t) && PREC[t] < PREC[ops[ops.length - 1]]) ||
          (!RIGHT_ASSOC.has(t) && PREC[t] <= PREC[ops[ops.length - 1]]))
      )
        output.push(ops.pop() as string);
      ops.push(t);
    }
  }
  while (ops.length) {
    const op = ops.pop() as string;
    if (op === '(') return null;
    output.push(op);
  }
  const stack: number[] = [];
  for (const t of output) {
    if (typeof t === 'number') stack.push(t);
    else if (t === 'u-') {
      const a = stack.pop();
      if (a === undefined) return null;
      stack.push(-a);
    } else {
      const b = stack.pop();
      const a = stack.pop();
      if (a === undefined || b === undefined) return null;
      let r: number;
      if (t === '+') r = a + b;
      else if (t === '-') r = a - b;
      else if (t === '*') r = a * b;
      else if (t === '/') r = a / b;
      else return null;
      if (!Number.isFinite(r)) return null;
      stack.push(r);
    }
  }
  if (stack.length !== 1) return null;
  return stack[0];
};

const clampNumber = (num: number, minNum?: number, maxNum?: number): number => {
  let result = num;
  if (minNum !== undefined && Number.isFinite(minNum) && result < minNum)
    result = minNum;
  if (maxNum !== undefined && Number.isFinite(maxNum) && result > maxNum)
    result = maxNum;
  return result;
};

// ----- internal context: lets <NumericInput/> reach Root state for expression eval -----
interface NumericContextValue {
  getInputElement: () => HTMLInputElement | null;
  setInputElement: (node: HTMLInputElement | null) => void;
  minNumber?: number;
  maxNumber?: number;
  isControlled: boolean;
  setInternalValue: (n: number | null) => void;
  emit: (n: number | null) => void;
}

const NumericContext = React.createContext<NumericContextValue | null>(null);

function assignRef<T>(ref: React.Ref<T> | undefined, value: T | null) {
  if (typeof ref === 'function') {
    ref(value);
  } else if (ref) {
    ref.current = value;
  }
}

// ----- Root -----
interface NumericInputRootProps extends Omit<
  React.ComponentProps<typeof NumberField.Root>,
  'value' | 'defaultValue' | 'min' | 'max' | 'step' | 'onValueChange'
> {
  value?: number | string;
  defaultValue?: number | string;
  min?: number | string;
  max?: number | string;
  nudgeAmount?: number;
  onValueChange?: (next: string) => void;
}

function NumericInputRoot({
  value,
  defaultValue,
  min,
  max,
  nudgeAmount = 1,
  onValueChange,
  className,
  children,
  ...props
}: NumericInputRootProps) {
  const minNumber = React.useMemo(
    () => (typeof min === 'string' ? Number(min) : min),
    [min],
  );
  const maxNumber = React.useMemo(
    () => (typeof max === 'string' ? Number(max) : max),
    [max],
  );

  const isControlled = value !== undefined;
  const [internalValue, setInternalValue] = React.useState<number | null>(() =>
    toNullableNumber(value ?? defaultValue),
  );
  const rootValue = isControlled ? toNullableNumber(value) : internalValue;

  const inputRef = React.useRef<HTMLInputElement | null>(null);
  const getInputElement = React.useCallback(() => inputRef.current, []);
  const setInputElement = React.useCallback((node: HTMLInputElement | null) => {
    inputRef.current = node;
  }, []);

  const emit = React.useCallback(
    (n: number | null) => {
      if (n === null) {
        onValueChange?.('');
      } else {
        onValueChange?.(trimTrailingZeros(String(n)));
      }
    },
    [onValueChange],
  );

  const handleValueChange = React.useCallback(
    (next: number | null) => {
      if (!isControlled) setInternalValue(next);
      emit(next);
    },
    [emit, isControlled],
  );

  const step = Number(nudgeAmount ?? 1);

  const ctx = React.useMemo<NumericContextValue>(
    () => ({
      getInputElement,
      setInputElement,
      minNumber,
      maxNumber,
      isControlled,
      setInternalValue,
      emit,
    }),
    [
      getInputElement,
      setInputElement,
      minNumber,
      maxNumber,
      isControlled,
      emit,
    ],
  );

  return (
    <NumericContext.Provider value={ctx}>
      <NumberField.Root
        {...props}
        value={rootValue}
        onValueChange={handleValueChange}
        min={minNumber}
        max={maxNumber}
        step={Number.isFinite(step) && step > 0 ? step : 1}
        data-slot='section'
        className={cn(
          'inline-flex h-6 items-center rounded-md',
          'has-data-scrubbing:cursor-ew-resize has-data-scrubbing:ring-blue-600! dark:has-data-scrubbing:ring-blue-400!',
          className,
        )}
      >
        {children}
      </NumberField.Root>
    </NumericContext.Provider>
  );
}

// ----- Input -----
type NumberFieldInputProps = React.ComponentProps<typeof NumberField.Input>;

function NumericInput({
  className,
  onBlur,
  onKeyDown,
  ref,
  ...props
}: NumberFieldInputProps & { ref?: React.Ref<HTMLInputElement> }) {
  const ctx = React.useContext(NumericContext);
  const inputRef = React.useCallback(
    (node: HTMLInputElement | null) => {
      ctx?.setInputElement(node);
      assignRef(ref, node);
    },
    [ctx, ref],
  );

  const tryEvaluateExpression = React.useCallback((): boolean => {
    if (!ctx) return false;
    const raw = ctx.getInputElement()?.value ?? '';
    if (!OPERATORS_REGEX.test(raw)) return false;
    const r = evaluateExpression(raw);
    if (r === null) return false;
    const clamped = clampNumber(r, ctx.minNumber, ctx.maxNumber);
    if (!ctx.isControlled) ctx.setInternalValue(clamped);
    ctx.emit(clamped);
    return true;
  }, [ctx]);

  const handleBlur: NumberFieldInputProps['onBlur'] = (e) => {
    tryEvaluateExpression();
    onBlur?.(e);
  };

  const handleKeyDown: NumberFieldInputProps['onKeyDown'] = (e) => {
    if (e.key === 'Enter') {
      if (tryEvaluateExpression()) {
        e.preventDefault();
        (e.currentTarget as HTMLInputElement).blur();
      }
    }
    onKeyDown?.(e);
  };

  return (
    <NumberField.Input
      {...props}
      data-slot='input'
      ref={inputRef}
      className={cn(INPUT_BASE_CLASS, 'flex-1', className)}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
    />
  );
}

// ----- ScrubArea -----
function ScrubAreaCursorIcon({ className }: { className?: string }) {
  return (
    <svg
      width='26'
      height='14'
      viewBox='0 0 24 14'
      fill='black'
      stroke='white'
      style={{ display: 'block' }}
      className={className}
    >
      <path d='M19.5 5.5L6.49737 5.51844V2L1 6.9999L6.5 12L6.49737 8.5L19.5 8.5V12L25 6.9999L19.5 2V5.5Z' />
    </svg>
  );
}

// A sizeless wrapper. The consumer decides the size, padding, and visual
// content via className + children. The cursor + horizontal scrub behavior
// are baked in.
function NumericScrubArea({
  className,
  children,
}: {
  className?: string;
  children?: React.ReactNode;
}) {
  return (
    <NumberField.ScrubArea
      direction='horizontal'
      pixelSensitivity={8}
      className={cn('cursor-ew-resize select-none', className)}
    >
      {children}
      <NumberField.ScrubAreaCursor className='pointer-events-none z-50'>
        <ScrubAreaCursorIcon />
      </NumberField.ScrubAreaCursor>
    </NumberField.ScrubArea>
  );
}

export { NumericInputRoot, NumericScrubArea, NumericInput };

'use client';

import React from 'react';
import chroma from 'chroma-js';
import { Input as BaseInput } from '@base-ui/react';
import { cn } from '@/lib/utils';
import { INPUT_BASE_CLASS } from './text-input';

const HEX_RE = /^([0-9a-fA-F]{3}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/;

const normalizeHex = (s: string): string => {
  const t = s.trim();
  return HEX_RE.test(t) ? `#${t}` : t;
};

const toStringValue = (v: unknown): string => (typeof v === 'string' ? v : '');

const formatHexNoHashUpper = (s: string): string => {
  return chroma(normalizeHex(s)).hex().slice(1).toUpperCase();
};

const getFormattedHexNoHashUpper = (s: string): string | null => {
  return chroma.valid(normalizeHex(s)) ? formatHexNoHashUpper(s) : null;
};

type BaseInputProps = Omit<React.ComponentProps<typeof BaseInput>, 'onChange'>;

interface ColorInputProps extends BaseInputProps {
  /**
   * Called with the normalized hex string (uppercase, no leading `#`)
   * whenever the user types a valid color, and on commit (blur / Enter).
   */
  onValueChange?: (next: string) => void;
}

function ColorInput({
  onValueChange,
  onBlur,
  onKeyDown,
  value,
  defaultValue,
  className,
  ...props
}: ColorInputProps) {
  type BaseInputChangeEvent = Parameters<
    NonNullable<React.ComponentProps<typeof BaseInput>['onChange']>
  >[0];
  type BaseInputBlurEvent = Parameters<
    NonNullable<BaseInputProps['onBlur']>
  >[0];
  type BaseInputKeyDownEvent = Parameters<
    NonNullable<BaseInputProps['onKeyDown']>
  >[0];

  const initial = toStringValue(value ?? defaultValue ?? '');
  const [inputValue, setInputValue] = React.useState<string>(initial);
  const isControlled = value !== undefined;
  const controlledValue = toStringValue(value);
  const [lastControlledValue, setLastControlledValue] =
    React.useState<string>(controlledValue);
  const controlledValidValue = isControlled
    ? getFormattedHexNoHashUpper(controlledValue)
    : null;
  const [lastControlledValidValue, setLastControlledValidValue] =
    React.useState<string | null>(controlledValidValue);
  const lastValidRef = React.useRef<string>(
    getFormattedHexNoHashUpper(initial) ?? '000000',
  );

  if (isControlled && controlledValue !== lastControlledValue) {
    setLastControlledValue(controlledValue);
    setInputValue(controlledValue);
  }

  if (
    isControlled &&
    controlledValidValue !== null &&
    controlledValidValue !== lastControlledValidValue
  ) {
    setLastControlledValidValue(controlledValidValue);
  }

  const handleChange = (e: BaseInputChangeEvent) => {
    const next = e.target.value;
    setInputValue(next);
    if (chroma.valid(normalizeHex(next))) {
      const hex = formatHexNoHashUpper(next);
      lastValidRef.current = hex;
      onValueChange?.(hex);
    }
  };

  const commit = () => {
    if (chroma.valid(normalizeHex(inputValue))) {
      const hex = formatHexNoHashUpper(inputValue);
      setInputValue(hex);
      lastValidRef.current = hex;
      onValueChange?.(hex);
    } else {
      const fallback = lastControlledValidValue ?? lastValidRef.current;
      setInputValue(fallback);
      onValueChange?.(fallback);
    }
  };

  const handleBlur = (e: BaseInputBlurEvent) => {
    commit();
    onBlur?.(e);
  };

  const handleKeyDown = (e: BaseInputKeyDownEvent) => {
    if (e.key === 'Enter') {
      commit();
      e.currentTarget.blur();
    }
    onKeyDown?.(e);
  };

  return (
    <BaseInput
      type='text'
      {...props}
      data-slot='input'
      value={inputValue}
      onChange={handleChange}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      className={cn(INPUT_BASE_CLASS, className)}
    />
  );
}

export { ColorInput };

'use client';

import type * as React from 'react';
import { cn } from '@/lib/utils';

// ─── Constants ──────────────────────────────────────────────────────────────

/** Classes applied to the InputGroup container (shared shell). */
const INPUT_GROUP_CLASS = [
  // base visual
  'bg-grey-100 dark:bg-grey-700 inline-flex h-6 items-center rounded-md',
  // ring states
  'ring ring-transparent hover:ring-grey-200 dark:hover:ring-grey-600',
  'focus-within:ring-blue-500! dark:focus-within:ring-blue-500!',
  'has-data-scrubbing:ring-blue-600! dark:has-data-scrubbing:ring-blue-400!',
  'has-[[aria-invalid=true]]:ring-red-500/20! dark:has-[[aria-invalid=true]]:ring-red-500/30!',
  // Hide phantom inputs rendered by base-ui NumberField.Root
  '[&>input[aria-hidden=true]]:!hidden',
  // ─── Spacing rules via data-slot sibling selectors ───
  // Addons are fixed 24px slots, so their centered contents already create visual gap.
  // Dividers only need added margin when the neighboring visible content is an input.
  '[&>[data-slot=input]+[data-slot=divider]]:ml-1',
  '[&>[data-slot=section]:has(>[data-slot=input]:last-child)+[data-slot=divider]]:ml-1',
  '[&>[data-slot=section]:has(>[data-slot=input]:last-child)+input[aria-hidden=true]+[data-slot=divider]]:ml-1',
  '[&>[data-slot=divider]+[data-slot=input]]:ml-1',
  '[&>[data-slot=divider]+[data-slot=section]:has(>[data-slot=input]:first-child)]:ml-1',
  // Group-owned input resets. The inputs expose stable slots, but do not import
  // group internals.
  '[&_[data-slot=input]]:h-full',
  '[&_[data-slot=input]]:rounded-none!',
  '[&_[data-slot=input]]:bg-transparent!',
  '[&_[data-slot=input]]:px-0!',
  '[&_[data-slot=input]]:ring-0!',
  '[&_[data-slot=input]]:ring-transparent!',
  '[&_[data-slot=input]]:hover:ring-transparent!',
  '[&_[data-slot=input]]:focus:ring-transparent!',
  'dark:[&_[data-slot=input]]:bg-transparent!',
  '[&>[data-slot=section]]:h-full',
  '[&>[data-slot=section]]:rounded-none!',
  '[&>[data-slot=section]]:ring-transparent!',
  '[&>[data-slot=section]]:hover:ring-transparent!',
  // First/last child input → padding from container edge
  '[&>[data-slot=input]:first-child]:pl-1.5!',
  '[&>[data-slot=input]:last-child]:pr-1.5!',
  '[&>[data-slot=section]:first-child>[data-slot=input]:first-child]:pl-1.5!',
  '[&>[data-slot=section]>[data-slot=input]:last-child]:pr-1.5!',
].join(' ');

// ─── InputGroup ─────────────────────────────────────────────────────────────

interface InputGroupProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
}

function InputGroup({ className, children, ...props }: InputGroupProps) {
  return (
    <div className={cn(INPUT_GROUP_CLASS, className)} {...props}>
      {children}
    </div>
  );
}

// ─── InputGroupAddon ────────────────────────────────────────────────────────

interface InputGroupAddonProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
}

/**
 * Fixed-size slot for icons, color chits, scrub-areas, or text labels.
 * Default 24×24 centered flex container.
 */
function InputGroupAddon({
  className,
  children,
  ...props
}: InputGroupAddonProps) {
  return (
    <div
      data-slot='addon'
      className={cn(
        'text-grey-500 flex size-6 shrink-0 items-center justify-center text-xs',
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
}

// ─── InputGroupDivider ──────────────────────────────────────────────────────

interface InputGroupDividerProps {
  className?: string;
}

/** Vertical 1px separator between logical sections. */
function InputGroupDivider({ className }: InputGroupDividerProps) {
  return (
    <div
      data-slot='divider'
      aria-hidden='true'
      className={cn(
        'bg-grey-200 dark:bg-grey-600 h-6 w-px shrink-0 self-center',
        className,
      )}
    />
  );
}

// ─── Exports ────────────────────────────────────────────────────────────────

export { InputGroup, InputGroupAddon, InputGroupDivider };
